const pick = (...vals) => vals.find((v) => v !== undefined && v !== null && String(v).trim() !== '');
const get = (obj, path) => path.split('.').reduce((acc, key) => acc?.[key], obj);

const input = $json || {};
const headers = input.headers || {};
const payload = input.body || input;
const data = payload.data || payload;
const key = data.key || payload.key || {};

const expectedSecret = String($env.INBOUND_WEBHOOK_SECRET || '').trim();
const receivedSecret = String(
  headers['x-inbound-secret']
    || headers['x_webhook_secret']
    || headers['x-webhook-secret']
    || payload.secret
    || payload.webhook_secret
    || ''
).trim();
const secret_ok = !expectedSecret || expectedSecret === receivedSecret;

const event = String(pick(payload.event, data.event, payload.type, payload.action, '')).toLowerCase();
const rawJid = String(pick(key.remoteJid, data.remoteJid, payload.remoteJid, data.from, payload.from, '')).trim();
const phone_norm = rawJid.replace(/@.+$/, '').replace(/\D/g, '');
const from_me = Boolean(pick(key.fromMe, data.fromMe, payload.fromMe, false));
const message_id = String(pick(key.id, data.messageId, payload.messageId, data.id, payload.id, '')).trim();

const text_original = String(pick(
  get(data, 'message.conversation'),
  get(data, 'message.extendedTextMessage.text'),
  get(data, 'message.imageMessage.caption'),
  get(data, 'message.videoMessage.caption'),
  get(data, 'message.buttonsResponseMessage.selectedDisplayText'),
  get(data, 'message.listResponseMessage.title'),
  get(payload, 'message.conversation'),
  get(payload, 'message.extendedTextMessage.text'),
  get(payload, 'message.imageMessage.caption'),
  get(payload, 'message.videoMessage.caption'),
  payload.text,
  payload.message,
  ''
)).trim();

const text_norm = text_original
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .toLowerCase()
  .replace(/\s+/g, ' ')
  .trim();

const is_group = /@g\.us$/.test(rawJid);
const is_status = rawJid === 'status@broadcast';
const is_inbound_text = secret_ok && !from_me && !!phone_norm && !is_group && !is_status && !!text_norm;

return [{
  json: {
    raw_payload: payload,
    event,
    raw_jid: rawJid,
    phone_norm,
    from_me,
    message_id,
    text_original,
    text_norm,
    is_group,
    is_status,
    secret_ok,
    is_inbound_text,
    received_at_iso: new Date().toISOString(),
  },
}];

const ttlMs = Math.max(60, Number($env.INBOUND_DEDUPE_TTL_SECONDS || 172800)) * 1000;
const windowSec = Math.max(30, Number($env.INBOUND_DEDUPE_TEXT_WINDOW_SECONDS || 600));
const maxKeys = Math.max(1000, Number($env.INBOUND_DEDUPE_MAX_KEYS || 50000));
const now = Date.now();

const hash = (input) => {
  const s = String(input || '');
  let h = 0;
  for (const c of s) h = ((h << 5) - h + c.charCodeAt(0)) | 0;
  return `h${Math.abs(h)}`;
};

const state = $getWorkflowStaticData('global');
const store = state.inbound_dedupe_v1 || {};

for (const [k, v] of Object.entries(store)) {
  if (!v || !v.ts || (now - Number(v.ts)) > ttlMs) delete store[k];
}

const messageKey = String($json.message_id || '').trim();
const dedupeByMessage = messageKey ? `msg:${messageKey}` : '';
const bucket = Math.floor(now / (windowSec * 1000));
const dedupeByText = `txt:${$json.phone_norm}:${hash($json.text_norm)}:${bucket}`;
const dedupe_key = dedupeByMessage || dedupeByText;

const is_duplicate = Boolean(store[dedupe_key]);
if (!is_duplicate) {
  store[dedupe_key] = {
    ts: now,
    phone: $json.phone_norm,
    message_id: messageKey,
  };
}

const entries = Object.entries(store);
if (entries.length > maxKeys) {
  const toDrop = entries
    .sort((a, b) => Number(a[1].ts || 0) - Number(b[1].ts || 0))
    .slice(0, entries.length - maxKeys);
  for (const [k] of toDrop) delete store[k];
}

state.inbound_dedupe_v1 = store;

return [{
  json: {
    ...$json,
    dedupe_key,
    is_duplicate,
  },
}];

const t = String($json.text_norm || '');

const rules = [
  { cls: 'negativo', w: 6, re: /\b(nao tenho interesse|sem interesse|nao quero|nao me chame|pare|parar|sair|stop|descad|remov(a|er)|cancele|cancelar)\b/ },
  { cls: 'positivo', w: 5, re: /\b(quero|tenho interesse|interesse sim|pode mandar|manda mais|vamos conversar|agendar|visita|disponibilidade|qual valor|preco)\b/ },
  { cls: 'negativo', w: 3, re: /\b(agora nao|depois|outro momento)\b/ },
  { cls: 'positivo', w: 2, re: /\b(ok|blz|perfeito|fechado|top)\b/ },
];

let pos = 0;
let neg = 0;
for (const r of rules) {
  if (r.re.test(t)) {
    if (r.cls === 'positivo') pos += r.w;
    if (r.cls === 'negativo') neg += r.w;
  }
}

if (/\bnao\b.{0,12}\b(quero|interesse|manda|envia|falar)\b/.test(t)) neg += 4;

let classificacao = 'neutro';
if (neg >= pos + 2) classificacao = 'negativo';
else if (pos >= neg + 2) classificacao = 'positivo';

const score = Number(Math.min(0.99, 0.55 + (Math.abs(pos - neg) / 12)).toFixed(2));

const blockOnNeg = String($env.INBOUND_BLOCK_ON_NEGATIVE || 'true').toLowerCase() === 'true';
const blockOnPos = String($env.INBOUND_BLOCK_ON_POSITIVE || 'false').toLowerCase() === 'true';
const bloquear_envio = (classificacao === 'negativo' && blockOnNeg) || (classificacao === 'positivo' && blockOnPos);

return [{
  json: {
    ...$json,
    classificacao,
    classificacao_score: score,
    bloquear_envio,
    provider_status_inbound: `INBOUND_${classificacao.toUpperCase()}`,
    erro_envio_inbound: classificacao === 'negativo' ? 'opt_out_inbound' : '',
    processed_at_iso: new Date().toISOString(),
  },
}];

const inbound = $('Classificar Resposta PT-BR').item.json;
const rows = $input.all();

const normalizeText = (value) => String(value || '')
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .toLowerCase()
  .trim();

const isValidBrLocal = (digits) => {
  if (!(digits.length === 10 || digits.length === 11)) return false;
  const ddd = digits.slice(0, 2);
  if (!/^[1-9][0-9]$/.test(ddd)) return false;
  if (digits.length === 11) return digits[2] === '9';
  return /^[2-5]/.test(digits[2]);
};

const allowNonBr = String($env.CAMPAIGN_ALLOW_NON_BR || 'false').toLowerCase() === 'true';
const normalizePhone = (value) => {
  const digits = String(value || '').replace(/\D/g, '');
  if (!digits) return '';
  if (allowNonBr) return (digits.length >= 10 && digits.length <= 15) ? digits : '';
  if (digits.startsWith('55')) {
    const local = digits.slice(2);
    return isValidBrLocal(local) ? digits : '';
  }
  return isValidBrLocal(digits) ? `55${digits}` : '';
};

const targetPhone = normalizePhone(inbound.phone_norm || inbound.raw_jid || '');
const fallbackStatus = 'Nao Enviado';

let matched = null;
for (const item of rows) {
  const row = item.json || {};
  const phone = normalizePhone(row.whatsapp || row.telefone || row.celular || row.phone || row.numero);
  if (!phone) continue;
  if (phone !== targetPhone) continue;
  matched = row;
  break;
}

if (!matched) {
  return [{
    json: {
      ...inbound,
      lead_found: false,
      orphan_reason: inbound.is_duplicate ? 'duplicado' : 'lead_nao_encontrado',
      status_envio_atual: fallbackStatus,
      status_envio_final: inbound.bloquear_envio ? 'Enviado' : fallbackStatus,
      row_number: -1,
    },
  }];
}

const statusAtual = String(matched.status_envio || '').trim() || fallbackStatus;
const statusFinal = inbound.bloquear_envio ? 'Enviado' : statusAtual;

return [{
  json: {
    ...inbound,
    ...matched,
    lead_found: true,
    row_number: Number(matched.row_number || -1),
    status_envio_atual: statusAtual,
    status_envio_final: statusFinal,
    orphan_reason: '',
    bloqueio_motivo: inbound.bloquear_envio ? `classificacao_${inbound.classificacao}` : '',
    inbound_phone_norm: targetPhone,
    inbound_nome_match: String(matched.nome || '').trim(),
    inbound_segmento_match: normalizeText(matched.segmento || matched.categoria || ''),
  },
}];
